package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;
    private File mockFile;
    private Charset charset;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockFile = mock(File.class);
        charset = Charset.defaultCharset();
    }

    @Test
    void testPrintCreatesCSVPrinter() throws IOException, NoSuchMethodException, IllegalAccessException, InvocationTargetException, InstantiationException {
        // Mock FileOutputStream constructor to avoid actual file IO
        // Since FileOutputStream is final and hard to mock, we use a dummy OutputStreamWriter via reflection

        // Create a dummy OutputStreamWriter to pass to CSVPrinter constructor
        OutputStreamWriter dummyWriter = mock(OutputStreamWriter.class);

        // Create a spy CSVFormat to override print(File, Charset) method to return a mock CSVPrinter
        CSVFormat spyFormat = spy(csvFormat);

        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Use reflection to get CSVPrinter constructor that takes (Appendable, CSVFormat)
        Constructor<CSVPrinter> printerConstructor = CSVPrinter.class.getDeclaredConstructor(Appendable.class, CSVFormat.class);
        printerConstructor.setAccessible(true);

        // Create a real CSVPrinter instance with dummyWriter and spyFormat
        CSVPrinter realPrinter = printerConstructor.newInstance(dummyWriter, spyFormat);

        // Stub spyFormat.print(File, Charset) to return the mockPrinter
        doReturn(mockPrinter).when(spyFormat).print(any(File.class), any(Charset.class));

        // Now call the method under test
        CSVPrinter printer = spyFormat.print(mockFile, charset);

        assertNotNull(printer);
        assertSame(mockPrinter, printer);
    }

    @Test
    void testPrintThrowsIOException() {
        // We simulate that passing null charset throws NullPointerException as per current implementation
        assertThrows(NullPointerException.class, () -> csvFormat.print(mockFile, null));
    }
}
